/**
 * @param {number[][]} points
 * @param {number[]} target
 * @return {number}
 */
function solve(points, target) {
    // Helper function to convert a point array to a unique string key
    const pointToKey = (p) => p.join(',');

    // Set of points available so far (initially all points)
    let currentPoints = new Set();
    for (const p of points) {
        currentPoints.add(pointToKey(p));
    }

    // Check for k=0
    const targetKey = pointToKey(target);
    if (currentPoints.has(targetKey)) {
        return 0;
    }

    let k = 0;
    let prevPointsCount = points.length;

    // Maximum possible k is related to the size of the reachable state space,
    // but since coordinates are small (0-6), the number of unique points is small (7^3 = 343).
    // We can stop when no new points are generated or we reach a safe limit.
    // Given the constraints, 350 iterations should be more than enough if a solution exists.
    const MAX_ITERATIONS = 500;

    while (k < MAX_ITERATIONS) {
        k++;
        const nextGeneratedPoints = new Set();
        const allAvailablePoints = [];

        // Reconstruct the list of points from the set keys for iteration
        for (const key of currentPoints) {
            allAvailablePoints.push(key.split(',').map(Number));
        }

        let newPointsGenerated = false;

        // Generate points for the k-th generation
        const numAvailable = allAvailablePoints.length;
        for (let i = 0; i < numAvailable; i++) {
            for (let j = i + 1; j < numAvailable; j++) {
                const p1 = allAvailablePoints[i];
                const p2 = allAvailablePoints[j];

                // Points are guaranteed to be different because i != j, 
                // and the problem states "两个不同的点" implies different (x, y, z) coordinates.
                // Since we are iterating over unique point keys in currentPoints, and i != j, 
                // p1 and p2 must have different coordinates if the initial points were distinct,
                // and any generated points are also distinct representations of coordinates.
                // However, the rule is "two *different* points a and b". If currentPoints contains
                // only unique coordinates, then i != j implies a != b.
                // Let's rely on the uniqueness of coordinates derived from currentPoints.

                const cx = Math.floor((p1[0] + p2[0]) / 2);
                const cy = Math.floor((p1[1] + p2[1]) / 2);
                const cz = Math.floor((p1[2] + p2[2]) / 2);

                const newPoint = [cx, cy, cz];
                const newKey = pointToKey(newPoint);

                if (!currentPoints.has(newKey)) {
                    nextGeneratedPoints.add(newKey);
                    newPointsGenerated = true;
                }
            }
        }

        // Add newly generated points to the set of available points
        for (const key of nextGeneratedPoints) {
            currentPoints.add(key);
        }

        // Check if the target was generated in this generation (or was already present, but we checked for k=0)
        if (currentPoints.has(targetKey)) {
            return k;
        }

        // If no new points were generated and the target wasn't found, we are stuck.
        // This implicitly handles the case where all pairs generate points already present.
        if (!newPointsGenerated) {
            return -1;
        }
    }

    // If loop terminates due to MAX_ITERATIONS (shouldn't happen given constraints if target is reachable)
    return -1;
}

