using namespace std;

typedef long long ll;

/**
 * Helper function to convert a point array to a unique string key.
 * Points are 3D: [x, y, z].
 */
string pointToKey(const vector<ll>& p) {
    stringstream ss;
    ss << p[0] << "," << p[1] << "," << p[2];
    return ss.str();
}

long long solve(std::vector<std::vector<long long>> points, std::vector<long long> target) {
    // Set of points available so far (stores string keys)
    set<string> currentPointsKeys;

    // 1. Initialize with points from the 0th generation
    for (const auto& p : points) {
        currentPointsKeys.insert(pointToKey(p));
    }

    // Check for k=0
    if (currentPointsKeys.count(pointToKey(target))) {
        return 0;
    }

    int k = 0;

    // Maximum possible number of unique points is bounded by (MaxCoord+1)^3 = 7^3 = 343.
    // Since the state space is finite, if the target is reachable, it must be reached 
    // before the set of points stops growing. A safe iteration limit is related to this size.
    const int MAX_ITERATIONS = 500; 

    while (k < MAX_ITERATIONS) {
        k++;
        set<string> nextGeneratedPointsKeys;
        bool newPointsGenerated = false;

        // Reconstruct the list of points from the set keys for iteration
        vector<vector<ll>> allAvailablePoints;
        for (const auto& key : currentPointsKeys) {
            vector<ll> p_coords;
            stringstream ss(key);
            string segment;
            while (getline(ss, segment, ',')) {
                p_coords.push_back(stoll(segment));
            }
            allAvailablePoints.push_back(p_coords);
        }

        // Generate points for the k-th generation
        int numAvailable = allAvailablePoints.size();

        // Iterate over all unique pairs of points
        for (int i = 0; i < numAvailable; i++) {
            for (int j = i + 1; j < numAvailable; j++) {
                const vector<ll>& p1 = allAvailablePoints[i];
                const vector<ll>& p2 = allAvailablePoints[j];

                // The problem requires "two *different* points a and b".
                // Since allAvailablePoints contains unique coordinate sets (due to set storage),
                // and we use i != j, the points p1 and p2 are distinct by coordinate value.

                // Calculate the midpoint c = [floor((x1 + x2) / 2), ...]
                ll cx = (p1[0] + p2[0]) / 2; // Integer division acts as floor for non-negative numbers
                ll cy = (p1[1] + p2[1]) / 2;
                ll cz = (p1[2] + p2[2]) / 2;

                vector<ll> newPoint = {cx, cy, cz};
                string newKey = pointToKey(newPoint);

                // Only consider points that are truly new to the overall set so far
                if (currentPointsKeys.find(newKey) == currentPointsKeys.end()) {
                    // Check if this new point was already scheduled for generation this round
                    if (nextGeneratedPointsKeys.find(newKey) == nextGeneratedPointsKeys.end()) {
                        nextGeneratedPointsKeys.insert(newKey);
                        newPointsGenerated = true;
                    }
                }
            }
        }

        // Add newly generated points to the set of available points
        for (const string& key : nextGeneratedPointsKeys) {
            currentPointsKeys.insert(key);
        }

        // Check if the target was generated in this generation or is now present
        if (currentPointsKeys.count(pointToKey(target))) {
            return k;
        }

        // If no new points were generated in this round, and the target wasn't found, we are stuck.
        if (!newPointsGenerated) {
            return -1;
        }
    }

    // Fallback return if MAX_ITERATIONS reached (should be covered by the newPointsGenerated check earlier)
    return -1;
}
